304	        }
305	
306	        if (unwrapped.isBigInt()) {
307	            return global.throw("YAML.stringify cannot serialize BigInt", .{});
308	        }
309	
310	        if (unwrapped.isBoolean()) {
311	            if (unwrapped.asBoolean()) {
312	                this.builder.append(.latin1, "true");
313	            } else {
314	                this.builder.append(.latin1, "false");
315	            }
316	            return;
317	        }
318	
319	        if (unwrapped.isString()) {
320	            const value_str = try unwrapped.toBunString(global);
321	            defer value_str.deref();
322	
323	            this.appendString(value_str);
324	            return;
325	        }
326	
327	        if (comptime Environment.ci_assert) {
328	            bun.assertWithLocation(unwrapped.isObject(), @src());
329	        }
330	
331	        const has_anchor: ?*AnchorAlias = has_anchor: {
332	            const anchor = this.known_collections.getPtr(unwrapped) orelse {
333	                break :has_anchor null;
334	            };
335	
336	            if (!anchor.used) {
337	                break :has_anchor null;
338	            }
339	
340	            break :has_anchor anchor;
341	        };
342	
343	        if (has_anchor) |anchor| {
