33	            line[0] == ';' or
34	            line[0] == '#') return true;
35	
36	        // check the rest is whitespace
37	        for (line) |c| {
38	            switch (c) {
39	                ' ', '\t', '\n', '\r' => {},
40	                '#', ';' => return true,
