108	static inline JSC::EncodedJSValue flattenArrayOfBuffersIntoArrayBufferOrUint8Array(JSGlobalObject* lexicalGlobalObject, JSValue arrayValue, size_t maxLength, bool asUint8Array)
109	{
110	    auto& vm = JSC::getVM(lexicalGlobalObject);
111	
112	    if (arrayValue.isUndefinedOrNull() || !arrayValue) {
113	        return JSC::JSValue::encode(JSC::JSArrayBuffer::create(vm, lexicalGlobalObject->arrayBufferStructure(), JSC::ArrayBuffer::create(static_cast<size_t>(0), 1)));
114	    }
115	
116	    auto throwScope = DECLARE_THROW_SCOPE(vm);
117	
118	    auto array = JSC::jsDynamicCast<JSC::JSArray*>(arrayValue);
119	    if (!array) [[unlikely]] {
120	        throwTypeError(lexicalGlobalObject, throwScope, "Argument must be an array"_s);
121	        return {};
122	    }
123	
124	    size_t arrayLength = array->length();
125	    const auto returnEmptyArrayBufferView = [&]() -> EncodedJSValue {
126	        if (asUint8Array) {
127	            RELEASE_AND_RETURN(throwScope, JSValue::encode(JSC::JSUint8Array::create(lexicalGlobalObject, lexicalGlobalObject->m_typedArrayUint8.get(lexicalGlobalObject), 0)));
128	        }
129	
130	        RELEASE_AND_RETURN(throwScope, JSValue::encode(JSC::JSArrayBuffer::create(vm, lexicalGlobalObject->arrayBufferStructure(), JSC::ArrayBuffer::create(static_cast<size_t>(0), 1))));
131	    };
132	    RETURN_IF_EXCEPTION(throwScope, {});
133	
134	    if (arrayLength < 1) {
135	        return returnEmptyArrayBufferView();
136	    }
137	
138	    size_t byteLength = 0;
139	    bool any_buffer = false;
140	    bool any_typed = false;
141	
142	    // Use an argument buffer to avoid calling `getIndex` more than once per element.
143	    // This is a small optimization
144	    MarkedArgumentBuffer args;
145	    args.ensureCapacity(arrayLength);
146	    if (args.hasOverflowed()) [[unlikely]] {
147	        throwOutOfMemoryError(lexicalGlobalObject, throwScope);
148	        return {};
149	    }
150	
151	    for (size_t i = 0; i < arrayLength; i++) {
152	        auto element = array->getIndex(lexicalGlobalObject, i);
153	        RETURN_IF_EXCEPTION(throwScope, {});
154	
155	        if (auto* typedArray = JSC::jsDynamicCast<JSC::JSArrayBufferView*>(element)) {
156	            if (typedArray->isDetached()) [[unlikely]] {
157	                return Bun::ERR::INVALID_STATE(throwScope, lexicalGlobalObject, "Cannot validate on a detached buffer"_s);
158	            }
159	            size_t current = typedArray->byteLength();
160	            any_typed = true;
161	            byteLength += current;
162	
163	            if (current > 0) {
164	                args.append(typedArray);
165	            }
166	        } else if (auto* arrayBuffer = JSC::jsDynamicCast<JSC::JSArrayBuffer*>(element)) {
167	            auto* impl = arrayBuffer->impl();
168	            if (!impl) [[unlikely]] {
169	                return Bun::ERR::INVALID_STATE(throwScope, lexicalGlobalObject, "Cannot validate on a detached buffer"_s);
170	            }
171	
172	            size_t current = impl->byteLength();
173	            any_buffer = true;
174	
175	            if (current > 0) {
176	                args.append(arrayBuffer);
177	            }
178	
179	            byteLength += current;
180	        } else {
181	            throwTypeError(lexicalGlobalObject, throwScope, "Expected TypedArray"_s);
182	            return {};
183	        }
184	    }
185	    byteLength = std::min(byteLength, maxLength);
186	
187	    if (byteLength == 0) {
188	        return returnEmptyArrayBufferView();
189	    }
190	
191	    auto buffer = JSC::ArrayBuffer::tryCreateUninitialized(byteLength, 1);
192	    if (!buffer) [[unlikely]] {
193	        throwTypeError(lexicalGlobalObject, throwScope, "Failed to allocate ArrayBuffer"_s);
194	        return {};
195	    }
196	
197	    size_t remain = byteLength;
198	    auto* head = reinterpret_cast<char*>(buffer->data());
199	
200	    if (!any_buffer) {
201	        for (size_t i = 0; i < args.size(); i++) {
202	            auto element = args.at(i);
203	            RETURN_IF_EXCEPTION(throwScope, {});
204	            auto* view = JSC::jsCast<JSC::JSArrayBufferView*>(element);
205	            size_t length = std::min(remain, view->byteLength());
206	            memcpy(head, view->vector(), length);
207	            remain -= length;
208	            head += length;
209	        }
210	    } else if (!any_typed) {
211	        for (size_t i = 0; i < args.size(); i++) {
212	            auto element = args.at(i);
213	            RETURN_IF_EXCEPTION(throwScope, {});
214	            auto* view = JSC::jsCast<JSC::JSArrayBuffer*>(element);
215	            size_t length = std::min(remain, view->impl()->byteLength());
216	            memcpy(head, view->impl()->data(), length);
217	            remain -= length;
218	            head += length;
219	        }
220	    } else {
221	        for (size_t i = 0; i < args.size(); i++) {
222	            auto element = args.at(i);
223	            RETURN_IF_EXCEPTION(throwScope, {});
224	            size_t length = 0;
225	            if (auto* view = JSC::jsDynamicCast<JSC::JSArrayBuffer*>(element)) {
226	                length = std::min(remain, view->impl()->byteLength());
227	                memcpy(head, view->impl()->data(), length);
228	            } else {
229	                auto* typedArray = JSC::jsCast<JSC::JSArrayBufferView*>(element);
230	                length = std::min(remain, typedArray->byteLength());
231	                memcpy(head, typedArray->vector(), length);
232	            }
233	
234	            remain -= length;
235	            head += length;
236	        }
237	    }
238	
239	    if (asUint8Array) {
240	        auto uint8array = JSC::JSUint8Array::create(lexicalGlobalObject, lexicalGlobalObject->m_typedArrayUint8.get(lexicalGlobalObject), WTF::move(buffer), 0, byteLength);
241	        RETURN_IF_EXCEPTION(throwScope, {});
242	        return JSValue::encode(uint8array);
243	    }
244	
245	    RELEASE_AND_RETURN(throwScope, JSValue::encode(JSC::JSArrayBuffer::create(vm, lexicalGlobalObject->arrayBufferStructure(), WTF::move(buffer))));
246	}
