461	    /// Returns index to skip or null if not an env substitution
462	    /// Invariants:
463	    /// - `i` must be an index into `val` that points to a '$' char
464	    ///
465	    /// npm/ini uses a regex pattern that will select the inner most ${...}
466	    /// Supports ${VAR} and ${VAR?} syntax:
467	    /// - ${VAR} - if undefined, returns null (leaves as-is)
468	    /// - ${VAR?} - if undefined, expands to empty string
469	    fn parseEnvSubstitution(this: *Parser, val: []const u8, start: usize, i: usize, unesc: *std.array_list.Managed(u8)) OOM!?usize {
470	        bun.debugAssert(val[i] == '$');
471	        var esc = false;
472	        if (i + "{}".len < val.len and val[i + 1] == '{') {
473	            var found_closing = false;
474	            var j = i + 2;
475	            while (j < val.len) : (j += 1) {
476	                switch (val[j]) {
477	                    '\\' => esc = !esc,
478	                    '$' => if (!esc) return this.parseEnvSubstitution(val, start, j, unesc),
479	                    '{' => if (!esc) return null,
480	                    '}' => if (!esc) {
481	                        found_closing = true;
482	                        break;
483	                    },
484	                    else => {},
485	                }
486	            }
487	
488	            if (!found_closing) return null;
489	
490	            if (start != i) {
491	                const missed = val[start..i];
492	                try unesc.appendSlice(missed);
493	            }
494	
495	            const env_var_raw = val[i + 2 .. j];
496	            const optional = env_var_raw.len > 0 and env_var_raw[env_var_raw.len - 1] == '?';
497	            const env_var = if (optional) env_var_raw[0 .. env_var_raw.len - 1] else env_var_raw;
498	
499	            // https://github.com/npm/cli/blob/534ad7789e5c61f579f44d782bdd18ea3ff1ee20/workspaces/config/lib/env-replace.js#L6
500	            if (this.env.get(env_var)) |expanded| {
501	                try unesc.appendSlice(expanded);
502	            } else if (!optional) {
503	                // Not found and not optional: return null to leave as-is
504	                return null;
505	            }
506	            // If optional and not found: expand to empty string (append nothing)
507	
508	            return j;
