50	
51	        // var duplicates = bun.StringArrayHashMapUnmanaged(u32){};
52	        // defer duplicates.deinit(allocator);
53	
54	        var rope_stack = std.heap.stackFallback(@sizeOf(Rope) * 6, arena_allocator);
55	        const ropealloc = rope_stack.get();
56	
57	        var skip_until_next_section: bool = false;
58	
59	        while (iter.next()) |line_| {
60	            const line = if (line_.len > 0 and line_[line_.len - 1] == '\r') line_[0 .. line_.len - 1] else line_;
