    if (isFloatLike(raw)) {
        const n = std.fmt.parseFloat(f64, raw) catch {
            const duped = allocator.dupe(u8, raw) catch return Expr.init(E.String, E.String.init(""), Loc.Empty);
            return Expr.init(E.String, E.String.init(duped), Loc.Empty);
        };
        return Expr.init(E.Number, E.Number{ .value = n }, Loc.Empty);
    }

    // Plain string
    const duped = allocator.dupe(u8, raw) catch return Expr.init(E.String, E.String.init(""), Loc.Empty);
    return Expr.init(E.String, E.String.init(duped), Loc.Empty);
