    if (std.mem.eql(u8, raw, "true")) return Expr.init(E.Boolean, E.Boolean{ .value = true }, Loc.Empty);
    if (std.mem.eql(u8, raw, "false")) return Expr.init(E.Boolean, E.Boolean{ .value = false }, Loc.Empty);

    // null
    if (std.mem.eql(u8, raw, "null")) return Expr.init(E.Null, E.Null{}, Loc.Empty);

