    if (s.len == 0) return false;
    var start: usize = 0;
    if (s[0] == '-' or s[0] == '+') {
        if (s.len == 1) return false;
        start = 1;
    }
    for (s[start..]) |c| {
        if (c < '0' or c > '9') return false;
    }
    return true;
}

fn isFloatLike(s: []const u8) bool {
    if (s.len == 0) return false;
    var start: usize = 0;
    if (s[0] == '-' or s[0] == '+') {
        if (s.len == 1) return false;
        start = 1;
    }
    var has_dot = false;
    var has_exp = false;
    var has_digit = false;
    var i = start;
    while (i < s.len) : (i += 1) {
        const c = s[i];
        switch (c) {
            '0'...'9' => has_digit = true,
            '.' => {
                if (has_dot or has_exp) return false;
                has_dot = true;
            },
            'e', 'E' => {
                if (has_exp or !has_digit) return false;
                has_exp = true;
                if (i + 1 < s.len and (s[i + 1] == '+' or s[i + 1] == '-')) i += 1;
