    }
    return has_digit and (has_dot or has_exp);
}

/// Traverse root using dot-separated path components, creating E.Object nodes
/// along the way if they don't exist, and return a pointer to the final object.
fn getOrCreateNestedObject(allocator: std.mem.Allocator, root: *E.Object, path: []const u8) OOM!*E.Object {
    var current = root;
    var part_iter = std.mem.splitScalar(u8, path, '.');
    while (part_iter.next()) |part| {
        const trimmed_part = std.mem.trim(u8, part, " \t");
        if (trimmed_part.len == 0) continue;

        if (current.get(trimmed_part)) |existing| {
            if (existing.data == .e_object) {
                current = existing.data.e_object;
            } else {
                // Key exists but is not an object — replace with a fresh object
                const new_obj = Expr.init(E.Object, E.Object{}, Loc.Empty);
                const key_copy = try allocator.dupe(u8, trimmed_part);
                try current.put(allocator, key_copy, new_obj);
                current = current.get(trimmed_part).?.data.e_object;
            }
        } else {
            const new_obj = Expr.init(E.Object, E.Object{}, Loc.Empty);
            const key_copy = try allocator.dupe(u8, trimmed_part);
            try current.put(allocator, key_copy, new_obj);
            current = current.get(trimmed_part).?.data.e_object;
        }
    }
    return current;
}

