// Stringifier
// ---------------------------------------------------------------------------

pub const Stringifier = struct {
    builder: bun.StringBuilder,
    allocator: std.mem.Allocator,

    pub fn init(allocator: std.mem.Allocator) Stringifier {
        return .{
            .builder = .{},
            .allocator = allocator,
        };
    }

    pub fn deinit(this: *Stringifier) void {
        this.builder.deinit(this.allocator);
    }

    /// Top-level stringify: emit bare key=value pairs first, then [section] blocks.
    pub fn stringify(
        this: *Stringifier,
        global: *jsc.JSGlobalObject,
        value: jsc.JSValue,
    ) (bun.JSError || OOM)!void {
        const object = try value.toObject(global);

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            object,
        );
        defer iter.deinit();

        // First pass: emit scalar / array properties (not objects)
        var scratch_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            object,
        );
        defer scratch_iter.deinit();

        while (try scratch_iter.next()) |prop_name| {
            const prop_value = scratch_iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
            if (isObjectValue(prop_value)) continue; // handled in second pass
            try this.emitKeyValue(global, prop_name, prop_value);
        }

        // Second pass: emit [section] blocks for object properties
        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
            if (!isObjectValue(prop_value)) continue;

            var section_name = bun.StringBuilder{};
            defer section_name.deinit(this.allocator);
            try section_name.append(this.allocator, prop_name.toUTF8(this.allocator));
            try this.emitSection(global, section_name.str(), prop_value, 0);
        }
    }

    fn isObjectValue(value: jsc.JSValue) bool {
        return value.isObject() and !value.isArray() and !value.jsType().isArrayLike();
    }

    fn emitKeyValue(
        this: *Stringifier,
        global: *jsc.JSGlobalObject,
        key: bun.String,
        value: jsc.JSValue,
    ) (bun.JSError || OOM)!void {
        if (value.isArray()) {
            // Emit each array element as a separate key=value line
            var arr_iter = try value.arrayIterator(global);
            while (try arr_iter.next()) |item| {
                if (item.isUndefined() or item.isFunction() or item.isSymbol()) continue;
                try this.builder.append(this.allocator, key.toUTF8(this.allocator));
                try this.builder.append(this.allocator, " = ");
                try this.appendScalar(global, item);
                try this.builder.append(this.allocator, "\n");
            }
            return;
        }

        try this.builder.append(this.allocator, key.toUTF8(this.allocator));
        try this.builder.append(this.allocator, " = ");
        try this.appendScalar(global, value);
        try this.builder.append(this.allocator, "\n");
    }

    fn emitSection(
        this: *Stringifier,
        global: *jsc.JSGlobalObject,
        section_path: []const u8,
        value: jsc.JSValue,
        depth: u32,
    ) (bun.JSError || OOM)!void {
        _ = depth;
        const obj = try value.toObject(global);

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            obj,
        );
        defer iter.deinit();

        // Check if there are any properties to emit
        if (iter.len == 0) return;

        // Emit section header
        try this.builder.append(this.allocator, "\n[");
        try this.builder.append(this.allocator, section_path);
        try this.builder.append(this.allocator, "]\n");

        // First pass: scalars and arrays
        var scalar_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            obj,
        );
        defer scalar_iter.deinit();

        while (try scalar_iter.next()) |prop_name| {
            const prop_value = scalar_iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
            if (isObjectValue(prop_value)) continue;
            try this.emitKeyValue(global, prop_name, prop_value);
        }

        // Second pass: nested objects (use dot-notation section names)
        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
            if (!isObjectValue(prop_value)) continue;

            const sub_name_utf8 = prop_name.toUTF8(this.allocator);
            const full_path = try std.fmt.allocPrint(
                this.allocator,
                "{s}.{s}",
                .{ section_path, sub_name_utf8 },
            );
            defer this.allocator.free(full_path);

            try this.emitSection(global, full_path, prop_value, 0);
        }
    }

    fn appendScalar(
        this: *Stringifier,
        global: *jsc.JSGlobalObject,
        value: jsc.JSValue,
    ) (bun.JSError || OOM)!void {
        if (value.isNull()) {
            try this.builder.append(this.allocator, "null");
            return;
        }
        if (value.isBoolean()) {
            try this.builder.append(this.allocator, if (value.asBoolean()) "true" else "false");
            return;
        }
        if (value.isInt32()) {
            var buf: [32]u8 = undefined;
            const s = std.fmt.bufPrint(&buf, "{d}", .{value.asInt32()}) catch unreachable;
            try this.builder.append(this.allocator, s);
            return;
        }
        if (value.isNumber()) {
            const n = value.asNumber();
            var buf: [64]u8 = undefined;
            const s = std.fmt.bufPrint(&buf, "{d}", .{n}) catch unreachable;
            try this.builder.append(this.allocator, s);
            return;
        }
        if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            const utf8 = str.toUTF8(bun.default_allocator);
            defer utf8.deinit();
            const slice = utf8.slice();
            // Quote if the value contains special characters
            if (needsQuoting(slice)) {
                try this.builder.appendChar(this.allocator, '"');
                try this.builder.append(this.allocator, slice);
                try this.builder.appendChar(this.allocator, '"');
            } else {
                try this.builder.append(this.allocator, slice);
            }
            return;
        }
        // Fallback: convert to string
        const str = try value.toBunString(global);
        defer str.deref();
        const utf8 = str.toUTF8(bun.default_allocator);
        defer utf8.deinit();
        try this.builder.append(this.allocator, utf8.slice());
    }

    /// Returns true if a value string needs to be double-quoted in INI output.
    fn needsQuoting(s: []const u8) bool {
        if (s.len == 0) return true;
        // Quote if starts/ends with whitespace
        if (s[0] == ' ' or s[0] == '\t' or s[s.len - 1] == ' ' or s[s.len - 1] == '\t') return true;
        for (s) |c| {
            switch (c) {
                '=', '[', ']', ';', '#', '\n', '\r', '"' => return true,
                else => {},
            }
        }
        return false;
    }
};

