    const allocator = arena.allocator();
    defer arena.deinit();

    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
    var ast_scope = ast_memory_allocator.enter(allocator);
    defer ast_scope.exit();

    var log = logger.Log.init(default_allocator);
    defer log.deinit();

    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();

    const source = &logger.Source.initPathString("input.ini", input_slice.slice());
    const parse_result = ini.parse(source, &log, allocator) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
    };

    return parse_result.toJS(allocator, globalThis) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        error.JSError => return error.JSError,
        error.JSTerminated => return error.JSTerminated,
        // INI parsing does not produce macros or identifiers
        else => unreachable,
    };
}

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value, const replacer, const _space = callFrame.argumentsAsArray(3);
    _ = _space; // INI format has no indentation concept

    value.ensureStillAlive();

    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
        return .js_undefined;
    }

    if (!replacer.isUndefinedOrNull()) {
        return global.throw("INI.stringify does not support the replacer argument", .{});
    }

    var stringifier: Stringifier = .init();
    defer stringifier.deinit();

    stringifier.stringify(global, value) catch |err| return switch (err) {
        error.OutOfMemory, error.JSError, error.JSTerminated => |js_err| js_err,
        error.StackOverflow => global.throwStackOverflow(),
    };

    return stringifier.builder.toString(global);
}

// ---------------------------------------------------------------------------
// Stringifier
// ---------------------------------------------------------------------------

const Stringifier = struct {
    builder: wtf.StringBuilder,
    stack_check: bun.StackCheck,

    const StringifyError = bun.JSError || bun.StackOverflow;

    pub fn init() Stringifier {
        return .{
            .builder = .init(),
            .stack_check = .init(),
        };
    }

    pub fn deinit(this: *Stringifier) void {
        this.builder.deinit();
    }

    /// Top-level stringify: emit bare key=value pairs first, then [section] blocks.
    pub fn stringify(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
        if (!this.stack_check.isSafeToRecurse()) return error.StackOverflow;

        // Accept objects; anything else → empty string
        if (!value.isObject() or value.isArray()) {
            return;
        }

        const object = try value.toObject(global);

        // Two iterators over the same object: first scalars, then object sections.
        // JSPropertyIterator is not rewindable so we need two.
        var scalar_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            object,
        );
        defer scalar_iter.deinit();

        var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            object,
        );
        defer section_iter.deinit();

        // First pass: scalars and arrays
        while (try scalar_iter.next()) |prop_name| {
            const prop_value = scalar_iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
            if (isPlainObject(prop_value)) continue;
            try this.emitKeyValue(global, prop_name, prop_value);
        }

        // Second pass: object sections
        while (try section_iter.next()) |prop_name| {
            const prop_value = section_iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
            if (!isPlainObject(prop_value)) continue;

            const name_slice = prop_name.toUTF8(bun.default_allocator);
            defer name_slice.deinit();
            try this.emitSection(global, name_slice.slice(), prop_value);
        }
    }

    fn isPlainObject(v: JSValue) bool {
        return v.isObject() and !v.isArray() and !v.jsType().isArrayLike();
    }

    fn emitKeyValue(this: *Stringifier, global: *jsc.JSGlobalObject, key: bun.String, value: JSValue) StringifyError!void {
        if (value.isArray()) {
            var arr_iter = try value.arrayIterator(global);
            while (try arr_iter.next()) |item| {
                if (item.isUndefined() or item.isFunction() or item.isSymbol()) continue;
                this.builder.append(.string, key);
                this.builder.append(.latin1, " = ");
                try this.appendScalar(global, item);
                this.builder.append(.lchar, '\n');
            }
            return;
        }

        this.builder.append(.string, key);
        this.builder.append(.latin1, " = ");
        try this.appendScalar(global, value);
        this.builder.append(.lchar, '\n');
    }

    fn emitSection(
        this: *Stringifier,
        global: *jsc.JSGlobalObject,
        section_path: []const u8,
        value: JSValue,
    ) StringifyError!void {
        if (!this.stack_check.isSafeToRecurse()) return error.StackOverflow;

        const object = try value.toObject(global);

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            object,
        );
        defer iter.deinit();

        if (iter.len == 0) return;

        // Emit section header
        this.builder.append(.lchar, '\n');
        this.builder.append(.lchar, '[');
        this.builder.append(.latin1, section_path);
        this.builder.append(.latin1, "]\n");

        var scalar_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            object,
        );
        defer scalar_iter.deinit();

        // First: scalars and arrays
        while (try scalar_iter.next()) |prop_name| {
            const prop_value = scalar_iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
            if (isPlainObject(prop_value)) continue;
            try this.emitKeyValue(global, prop_name, prop_value);
        }

        // Then: nested objects (dot-notation section names)
        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
            if (!isPlainObject(prop_value)) continue;

            const sub_name = prop_name.toUTF8(bun.default_allocator);
            defer sub_name.deinit();

            // Build "section_path.sub_name" into a small stack buffer first, fall back to heap
            var buf: [512]u8 = undefined;
            const full_path = std.fmt.bufPrint(&buf, "{s}.{s}", .{ section_path, sub_name.slice() }) catch blk: {
                // Longer than 512 bytes — heap allocate
                const heap = try bun.default_allocator.alloc(
                    u8,
                    section_path.len + 1 + sub_name.slice().len,
                );
                @memcpy(heap[0..section_path.len], section_path);
                heap[section_path.len] = '.';
                @memcpy(heap[section_path.len + 1 ..], sub_name.slice());
                break :blk heap;
            };
            const need_free = full_path.ptr != &buf;
            defer if (need_free) bun.default_allocator.free(full_path);

            try this.emitSection(global, full_path, prop_value);
        }
    }

    fn appendScalar(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
        if (value.isNull()) {
            this.builder.append(.latin1, "null");
            return;
        }
        if (value.isBoolean()) {
            this.builder.append(.latin1, if (value.asBoolean()) "true" else "false");
            return;
        }
        if (value.isInt32()) {
            this.builder.append(.int, value.asInt32());
            return;
        }
        if (value.isNumber()) {
            this.builder.append(.double, value.asNumber());
            return;
        }
        if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            if (needsQuoting(str)) {
                this.builder.append(.lchar, '"');
                this.builder.append(.string, str);
                this.builder.append(.lchar, '"');
            } else {
                this.builder.append(.string, str);
            }
            return;
        }
        // Fallback: coerce to string
        const str = try value.toBunString(global);
        defer str.deref();
        this.builder.append(.string, str);
    }

    /// Returns true if a string value needs to be double-quoted in INI output.
    fn needsQuoting(str: bun.String) bool {
        const len = str.length();
        if (len == 0) return true;
        // Quote if starts/ends with whitespace
        const first = str.charAt(0);
        const last = str.charAt(len - 1);
        if (first == ' ' or first == '\t' or last == ' ' or last == '\t') return true;
        // Quote if contains special INI characters
        for (0..len) |i| {
            switch (str.charAt(i)) {
                '=', '[', ']', ';', '#', '\n', '\r', '"' => return true,
                else => {},
            }
        }
        return false;
    }
};

// ---------------------------------------------------------------------------
// Imports
// ---------------------------------------------------------------------------

