        @export(&BunObject.write, .{ .name = callbackName("write") });
        @export(&BunObject.zstdCompressSync, .{ .name = callbackName("zstdCompressSync") });
        @export(&BunObject.zstdDecompressSync, .{ .name = callbackName("zstdDecompressSync") });
