/**
 * Tests for the public Bun.INI API (parse and stringify).
 *
 * NOTE: This file tests the PUBLIC Bun.INI API only.
 * The existing ini.test.ts tests the internal npm INI parser
 * via bun:internal-for-testing and is completely separate.
 */
import { INI } from "bun";
import { describe, expect, test } from "bun:test";

describe("Bun.INI", () => {
  describe("parse", () => {
    test("basic key=value pairs", () => {
      const result = INI.parse("name = hello\nversion = 1.0");
      expect(result).toEqual({ name: "hello", version: "1.0" });
    });

    test("key=value without spaces around equals", () => {
      const result = INI.parse("key=value");
      expect(result).toEqual({ key: "value" });
    });

    test("key=value with extra whitespace", () => {
      const result = INI.parse("  key  =  value  ");
      expect(result).toEqual({ key: "value" });
    });

    test("section creates nested object", () => {
      const result = INI.parse("[section]\nkey = value");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("multiple sections", () => {
      const input = `
[server]
host = localhost
port = 8080

[database]
host = 127.0.0.1
port = 5432
`;
      expect(result).toEqual({
        server: { host: "localhost", port: 8080 },
        database: { host: "127.0.0.1", port: 5432 },
      });
      const result = INI.parse(input);
      expect(result).toEqual({
        server: { host: "localhost", port: 8080 },
        database: { host: "127.0.0.1", port: 5432 },
      });
    });

    test("top-level keys and sections mixed", () => {
      const input = "name = app\n[db]\nhost = localhost";
      const result = INI.parse(input);
      expect(result).toEqual({ name: "app", db: { host: "localhost" } });
    });

    test("semicolon comments are ignored", () => {
      const input = "; this is a comment\nkey = value";
      const result = INI.parse(input);
      expect(result).toEqual({ key: "value" });
    });

    test("hash comments are ignored", () => {
      const input = "# this is a comment\nkey = value";
      const result = INI.parse(input);
      expect(result).toEqual({ key: "value" });
    });

    test("inline comments are stripped", () => {
      const result = INI.parse("key = value ; inline comment");
      expect(result).toEqual({ key: "value" });
    });

    test("inline hash comments are stripped", () => {
      const result = INI.parse("key = value # inline comment");
      expect(result).toEqual({ key: "value" });
    });

    test("blank lines are ignored", () => {
      const result = INI.parse("\n\nkey = value\n\n");
      expect(result).toEqual({ key: "value" });
    });

    test("boolean true", () => {
      const result = INI.parse("enabled = true");
      expect(result).toEqual({ enabled: true });
    });

    test("boolean false", () => {
      const result = INI.parse("enabled = false");
      expect(result).toEqual({ enabled: false });
    });

    test("null value", () => {
      const result = INI.parse("value = null");
      expect(result).toEqual({ value: null });
    });

    test("integer value", () => {
      const result = INI.parse("port = 5432");
      expect((result as any).port).toBe(5432);
      expect(typeof (result as any).port).toBe("number");
    });

    test("negative integer", () => {
      const result = INI.parse("offset = -10");
      expect((result as any).offset).toBe(-10);
    });

    test("float value", () => {
      const result = INI.parse("ratio = 3.14");
      expect((result as any).ratio).toBeCloseTo(3.14);
    });

    test("double-quoted string value", () => {
      const result = INI.parse('greeting = "hello world"');
      expect(result).toEqual({ greeting: "hello world" });
    });

    test("single-quoted string value", () => {
      const result = INI.parse("greeting = 'hello world'");
      expect(result).toEqual({ greeting: "hello world" });
    });

    test("quoted string preserves numeric-looking content as string", () => {
      const result = INI.parse('code = "42"');
      expect(typeof (result as any).code).toBe("string");
      expect((result as any).code).toBe("42");
    });

    test("dot-notation section creates nested objects", () => {
      const input = "[server.tls]\ncert = /path/to/cert";
      const result = INI.parse(input);
      expect(result).toEqual({ server: { tls: { cert: "/path/to/cert" } } });
    });

    test("multiple dot-notation sections", () => {
      const input = "[a.b]\nkey = 1\n[a.c]\nkey = 2";
      const result = INI.parse(input);
      expect(result).toEqual({ a: { b: { key: 1 }, c: { key: 2 } } });
    });

    test("empty section", () => {
      const result = INI.parse("[empty]");
      expect(result).toEqual({ empty: {} });
    });

    test("empty string input", () => {
      const result = INI.parse("");
      expect(result).toEqual({});
    });

    test("only comments", () => {
      const result = INI.parse("; just a comment\n# another comment");
      expect(result).toEqual({});
    });

    test("CRLF line endings", () => {
      const result = INI.parse("key = value\r\n[section]\r\nfoo = bar");
      expect(result).toEqual({ key: "value", section: { foo: "bar" } });
    });

    test("leading whitespace on key lines", () => {
      const result = INI.parse("  key = value");
      expect(result).toEqual({ key: "value" });
    });

    test("returns plain object (not null)", () => {
      const result = INI.parse("key = value");
      expect(result).not.toBeNull();
      expect(typeof result).toBe("object");
    });

    test("throws on undefined input", () => {
      expect(() => INI.parse(undefined as any)).toThrow();
    });

    test("throws on null input", () => {
      expect(() => INI.parse(null as any)).toThrow();
    });

    test("__proto__ key is skipped (prototype pollution guard)", () => {
      const result = INI.parse("__proto__ = bad") as any;
      expect(Object.prototype.toString.call(result)).toBe("[object Object]");
      expect(result.__proto__).toBe(Object.prototype); // not "bad"
    });
  });

  describe("stringify", () => {
    test("top-level scalar values", () => {
      const result = INI.stringify({ name: "app", debug: false, port: 3000 });
      expect(result).toContain("name = app");
      expect(result).toContain("debug = false");
      expect(result).toContain("port = 3000");
    });

    test("object becomes a section", () => {
      const result = INI.stringify({ db: { host: "localhost", port: 5432 } });
      expect(result).toContain("[db]");
      expect(result).toContain("host = localhost");
      expect(result).toContain("port = 5432");
    });

    test("top-level values come before sections", () => {
      const result = INI.stringify({ name: "app", db: { host: "localhost" } });
      const namePos = result.indexOf("name = app");
      const sectionPos = result.indexOf("[db]");
      expect(namePos).toBeGreaterThanOrEqual(0);
      expect(sectionPos).toBeGreaterThanOrEqual(0);
      expect(namePos).toBeLessThan(sectionPos);
    });

    test("nested objects use dot-notation section names", () => {
      const result = INI.stringify({ server: { tls: { cert: "/path" } } });
      expect(result).toContain("[server.tls]");
      expect(result).toContain("cert = /path");
    });

    test("boolean values", () => {
      const result = INI.stringify({ enabled: true, debug: false });
      expect(result).toContain("enabled = true");
      expect(result).toContain("debug = false");
    });

    test("null value", () => {
      const result = INI.stringify({ value: null });
      expect(result).toContain("value = null");
    });

    test("number value", () => {
      const result = INI.stringify({ port: 8080 });
      expect(result).toContain("port = 8080");
    });

    test("string with special chars is quoted", () => {
      const result = INI.stringify({ key: "value=with=equals" });
      // Value contains '=' which requires quoting
      expect(result).toContain('"value=with=equals"');
    });

    test("empty string value is quoted", () => {
      const result = INI.stringify({ key: "" });
      expect(result).toContain('key = ""');
    });

    test("undefined value is skipped", () => {
      const result = INI.stringify({ defined: "yes", undef: undefined });
      expect(result).toContain("defined = yes");
      expect(result).not.toContain("undef");
    });

    test("function value is skipped", () => {
      const result = INI.stringify({ fn: () => {}, name: "app" });
      expect(result).toContain("name = app");
      expect(result).not.toContain("fn");
    });

    test("symbol value is skipped", () => {
      const result = INI.stringify({ sym: Symbol("x"), name: "app" });
      expect(result).toContain("name = app");
      expect(result).not.toContain("sym");
    });

    test("undefined input returns undefined", () => {
      expect(INI.stringify(undefined)).toBeUndefined();
    });

    test("function input returns undefined", () => {
      expect(INI.stringify(() => {})).toBeUndefined();
    });

    test("symbol input returns undefined", () => {
      expect(INI.stringify(Symbol("x") as any)).toBeUndefined();
    });

    test("throws when replacer is provided", () => {
      expect(() => INI.stringify({ key: "val" }, (k: string, v: unknown) => v as any)).toThrow(
        "replacer",
      );
    });

    test("round-trip: parse(stringify(obj)) equals original for flat object", () => {
      const original = { name: "app", port: 8080, debug: false };
      const round_trip = INI.parse(INI.stringify(original)) as typeof original;
      expect(round_trip.name).toBe("app");
      expect(round_trip.port).toBe(8080);
      expect(round_trip.debug).toBe(false);
    });

    test("round-trip: parse(stringify(obj)) equals original for nested object", () => {
      const original = {
        name: "app",
        db: { host: "localhost", port: 5432 },
      };
      const round_trip = INI.parse(INI.stringify(original)) as any;
      expect(round_trip.name).toBe("app");
      expect(round_trip.db.host).toBe("localhost");
      expect(round_trip.db.port).toBe(5432);
    });

    test("empty object produces empty string", () => {
      const result = INI.stringify({});
      expect(result).toBe("");
    });

    test("non-object input produces empty string", () => {
      // Numbers, strings, etc. are not INI-serialisable objects
      expect(INI.stringify(42 as any)).toBe("");
      expect(INI.stringify("hello" as any)).toBe("");
    });
  });
});

