    test("function input returns undefined", () => {
      expect(INI.stringify(() => {})).toBeUndefined();
    });

    test("symbol input returns undefined", () => {
      expect(INI.stringify(Symbol("x") as any)).toBeUndefined();
    });

    test("throws when replacer is provided", () => {
      expect(() => INI.stringify({ key: "val" }, (k: string, v: unknown) => v as any)).toThrow(
        "replacer",
      );
    });

    test("round-trip: parse(stringify(obj)) equals original for flat object", () => {
      const original = { name: "app", port: 8080, debug: false };
      const round_trip = INI.parse(INI.stringify(original)) as typeof original;
      expect(round_trip.name).toBe("app");
      expect(round_trip.port).toBe(8080);
      expect(round_trip.debug).toBe(false);
    });

    test("round-trip: parse(stringify(obj)) equals original for nested object", () => {
      const original = {
        name: "app",
        db: { host: "localhost", port: 5432 },
      };
      const round_trip = INI.parse(INI.stringify(original)) as any;
      expect(round_trip.name).toBe("app");
      expect(round_trip.db.host).toBe("localhost");
      expect(round_trip.db.port).toBe(5432);
    });

    test("empty object produces empty string", () => {
      const result = INI.stringify({});
      expect(result).toBe("");
    });

    test("non-object input produces empty string", () => {
      // Numbers, strings, etc. are not INI-serialisable objects
      expect(INI.stringify(42 as any)).toBe("");
      expect(INI.stringify("hello" as any)).toBe("");
    });
  });
});

