1	/// Self-contained INI parser for Bun.INI
2	///
3	/// Supports:
4	///   - Sections:   [section] and dot-notation [outer.inner]
5	///   - Key=value:  key = value  or  key=value  (whitespace trimmed)
6	///   - Comments:   ; comment  and  # comment  (whole-line or inline)
7	///   - Values:     type-inferred (true/false → bool, numbers → f64, else string)
8	///   - Quoted:     "string" and 'string' → kept as strings (quotes stripped)
9	///
10	/// This file intentionally does NOT import src/ini.zig (the npm-specific parser).
11	
12	const OOM = std.mem.Allocator.Error;
13	
14	/// Parse INI text and return the root E.Object Expr.
15	/// Sections become nested E.Object values.
16	/// Dot-notation section names (e.g. [outer.inner]) create deeply nested objects.
17	pub fn parse(source: *const logger.Source, log: *logger.Log, allocator: std.mem.Allocator) OOM!Expr {
18	    _ = log; // reserved for future diagnostic messages
19	
20	    const src = source.contents;
21	
22	    var root = Expr.init(E.Object, E.Object{}, Loc.Empty);
23	
24	    // current section object; points into root when no section is active
25	    var head: *E.Object = root.data.e_object;
26	
27	    var iter = std.mem.splitScalar(u8, src, '\n');
28	    while (iter.next()) |raw_line| {
29	        // Strip \r for CRLF files
30	        const line = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
31	            raw_line[0 .. raw_line.len - 1]
32	        else
33	            raw_line;
34	
35	        // Trim leading whitespace
36	        const trimmed = std.mem.trimLeft(u8, line, " \t");
37	
38	        // Skip blank lines and comment lines
39	        if (trimmed.len == 0 or trimmed[0] == ';' or trimmed[0] == '#') continue;
40	
41	        // --- Section header: [name] or [outer.inner] ---
42	        if (trimmed[0] == '[') {
43	            const close = std.mem.indexOfScalar(u8, trimmed, ']') orelse continue;
44	            // Ensure nothing but whitespace after ']'
45	            const after = std.mem.trimRight(u8, trimmed[close + 1 ..], " \t");
46	            if (after.len > 0) continue; // malformed — skip
47	
48	            const section_name = std.mem.trim(u8, trimmed[1..close], " \t");
49	            if (section_name.len == 0) continue;
50	
51	            // Navigate / create nested objects for dot-separated components
52	            head = try getOrCreateNestedObject(allocator, root.data.e_object, section_name);
53	            continue;
54	        }
55	
56	        // --- Key = value ---
57	        const eq_pos = std.mem.indexOfScalar(u8, trimmed, '=') orelse continue;
58	        const raw_key = std.mem.trim(u8, trimmed[0..eq_pos], " \t");
59	        if (raw_key.len == 0) continue;
60	
61	        // Skip __proto__ to prevent prototype pollution
62	        if (std.mem.eql(u8, raw_key, "__proto__")) continue;
63	
64	        const raw_val = std.mem.trim(u8, trimmed[eq_pos + 1 ..], " \t");
65	
66	        // Strip inline comments from value (anything after unquoted # or ;)
67	        const stripped_val = stripInlineComment(raw_val);
68	
69	        const value = try parseValue(allocator, stripped_val);
70	
71	        // Copy key into allocator memory so it outlives the input slice
72	        const key_copy = try allocator.dupe(u8, raw_key);
73	        try head.put(allocator, key_copy, value);
74	    }
75	
76	    return root;
77	}
78	
79	// ---------------------------------------------------------------------------
80	// Value parsing helpers
81	// ---------------------------------------------------------------------------
82	
83	/// Parse a raw value string into an Expr.
84	/// Quoted strings → E.String (quotes stripped).
85	/// "true"/"false" → E.Boolean.
86	/// "null" → E.Null.
87	/// Numeric strings → E.Number.
88	/// Everything else → E.String.
89	fn parseValue(allocator: std.mem.Allocator, raw: []const u8) OOM!Expr {
90	    if (raw.len == 0) return Expr.init(E.String, E.String.init(""), Loc.Empty);
91	
92	    // Double-quoted string
93	    if (raw.len >= 2 and raw[0] == '"' and raw[raw.len - 1] == '"') {
94	        const inner = raw[1 .. raw.len - 1];
95	        const duped = try allocator.dupe(u8, inner);
96	        return Expr.init(E.String, E.String.init(duped), Loc.Empty);
97	    }
98	
99	    // Single-quoted string
100	    if (raw.len >= 2 and raw[0] == '\'' and raw[raw.len - 1] == '\'') {
101	        const inner = raw[1 .. raw.len - 1];
102	        const duped = try allocator.dupe(u8, inner);
103	        return Expr.init(E.String, E.String.init(duped), Loc.Empty);
104	    }
105	
106	    // Boolean
107	    if (std.mem.eql(u8, raw, "true")) return Expr.init(E.Boolean, E.Boolean{ .value = true }, Loc.Empty);
108	    if (std.mem.eql(u8, raw, "false")) return Expr.init(E.Boolean, E.Boolean{ .value = false }, Loc.Empty);
109	
110	    // null
111	    if (std.mem.eql(u8, raw, "null")) return Expr.init(E.Null, E.Null{}, Loc.Empty);
112	
113	    // Integer (no decimal point, no exponent)
114	    if (isIntegerLike(raw)) {
115	        if (std.fmt.parseFloat(f64, raw)) |n| {
116	            return Expr.init(E.Number, E.Number{ .value = n }, Loc.Empty);
117	        } else |_| {}
118	    }
119	
120	    // Float
121	    if (isFloatLike(raw)) {
122	        if (std.fmt.parseFloat(f64, raw)) |n| {
123	            return Expr.init(E.Number, E.Number{ .value = n }, Loc.Empty);
124	        } else |_| {}
125	    }
126	
127	    // Plain string
128	    const duped = try allocator.dupe(u8, raw);
129	    return Expr.init(E.String, E.String.init(duped), Loc.Empty);
130	}
131	
132	/// Strip an inline comment (unquoted # or ;) from a value string.
133	/// Returns the trimmed value before the comment.
134	fn stripInlineComment(raw: []const u8) []const u8 {
135	    var in_double_quote = false;
136	    var in_single_quote = false;
137	    var i: usize = 0;
138	    while (i < raw.len) : (i += 1) {
139	        const c = raw[i];
140	        if (c == '"' and !in_single_quote) {
141	            in_double_quote = !in_double_quote;
142	        } else if (c == '\'' and !in_double_quote) {
143	            in_single_quote = !in_single_quote;
144	        } else if (!in_double_quote and !in_single_quote and (c == '#' or c == ';')) {
145	            return std.mem.trimRight(u8, raw[0..i], " \t");
146	        }
147	    }
148	    return raw;
149	}
150	
151	fn isIntegerLike(s: []const u8) bool {
152	    if (s.len == 0) return false;
153	    var start: usize = 0;
154	    if (s[0] == '-' or s[0] == '+') {
155	        if (s.len == 1) return false;
156	        start = 1;
157	    }
158	    for (s[start..]) |c| {
159	        if (c < '0' or c > '9') return false;
160	    }
161	    return true;
162	}
163	
164	fn isFloatLike(s: []const u8) bool {
165	    if (s.len == 0) return false;
166	    var start: usize = 0;
167	    if (s[0] == '-' or s[0] == '+') {
168	        if (s.len == 1) return false;
169	        start = 1;
170	    }
171	    var has_dot = false;
172	    var has_exp = false;
173	    var has_digit = false;
174	    var i = start;
175	    while (i < s.len) : (i += 1) {
176	        const c = s[i];
177	        switch (c) {
178	            '0'...'9' => has_digit = true,
179	            '.' => {
180	                if (has_dot or has_exp) return false;
181	                has_dot = true;
182	            },
183	            'e', 'E' => {
184	                if (has_exp or !has_digit) return false;
185	                has_exp = true;
186	                if (i + 1 < s.len and (s[i + 1] == '+' or s[i + 1] == '-')) i += 1;
187	            },
188	            else => return false,
189	        }
190	    }
191	    return has_digit and (has_dot or has_exp);
192	}
193	
194	/// Traverse root using dot-separated path components, creating E.Object nodes
195	/// along the way if they don't exist, and return a pointer to the final object.
196	fn getOrCreateNestedObject(allocator: std.mem.Allocator, root: *E.Object, path: []const u8) OOM!*E.Object {
197	    var current = root;
198	    var part_iter = std.mem.splitScalar(u8, path, '.');
199	    while (part_iter.next()) |part| {
200	        const trimmed_part = std.mem.trim(u8, part, " \t");
201	        if (trimmed_part.len == 0) continue;
202	
203	        if (current.get(trimmed_part)) |existing| {
204	            if (existing.data == .e_object) {
205	                current = existing.data.e_object;
206	            } else {
207	                // Key exists but is not an object — replace with a fresh object
208	                const new_obj = Expr.init(E.Object, E.Object{}, Loc.Empty);
209	                const key_copy = try allocator.dupe(u8, trimmed_part);
210	                try current.put(allocator, key_copy, new_obj);
211	                current = current.get(trimmed_part).?.data.e_object;
212	            }
213	        } else {
214	            const new_obj = Expr.init(E.Object, E.Object{}, Loc.Empty);
215	            const key_copy = try allocator.dupe(u8, trimmed_part);
216	            try current.put(allocator, key_copy, new_obj);
217	            current = current.get(trimmed_part).?.data.e_object;
218	        }
219	    }
220	    return current;
221	}
222	
223	// ---------------------------------------------------------------------------
224	// Imports
225	// ---------------------------------------------------------------------------
226	
227	const std = @import("std");
