/// Self-contained INI parser for Bun.INI
///
/// Supports:
///   - Sections:   [section] and dot-notation [outer.inner]
///   - Key=value:  key = value  or  key=value  (whitespace trimmed)
///   - Comments:   ; comment  and  # comment  (whole-line or inline)
///   - Values:     type-inferred (true/false → bool, numbers → f64, else string)
///   - Quoted:     "string" and 'string' → kept as strings (quotes stripped)
///
/// This file intentionally does NOT import src/ini.zig (the npm-specific parser).

const OOM = std.mem.Allocator.Error;

/// Parse INI text and return the root E.Object Expr.
/// Sections become nested E.Object values.
/// Dot-notation section names (e.g. [outer.inner]) create deeply nested objects.
pub fn parse(source: *const logger.Source, log: *logger.Log, allocator: std.mem.Allocator) OOM!Expr {
    _ = log; // reserved for future diagnostic messages

    const src = source.contents;

    var root = Expr.init(E.Object, E.Object{}, Loc.Empty);

    // current section object; points into root when no section is active
    var head: *E.Object = root.data.e_object;

    var iter = std.mem.splitScalar(u8, src, '\n');
    while (iter.next()) |raw_line| {
        // Strip \r for CRLF files
        const line = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;

        // Trim leading whitespace
        const trimmed = std.mem.trimLeft(u8, line, " \t");

        // Skip blank lines and comment lines
        if (trimmed.len == 0 or trimmed[0] == ';' or trimmed[0] == '#') continue;

        // --- Section header: [name] or [outer.inner] ---
        if (trimmed[0] == '[') {
            const close = std.mem.indexOfScalar(u8, trimmed, ']') orelse continue;
            // Ensure nothing but whitespace after ']'
            const after = std.mem.trimRight(u8, trimmed[close + 1 ..], " \t");
            if (after.len > 0) continue; // malformed — skip

            const section_name = std.mem.trim(u8, trimmed[1..close], " \t");
            if (section_name.len == 0) continue;

            // Navigate / create nested objects for dot-separated components
            head = try getOrCreateNestedObject(allocator, root.data.e_object, section_name);
            continue;
        }

        // --- Key = value ---
        const eq_pos = std.mem.indexOfScalar(u8, trimmed, '=') orelse continue;
        const raw_key = std.mem.trim(u8, trimmed[0..eq_pos], " \t");
        if (raw_key.len == 0) continue;

        // Skip __proto__ to prevent prototype pollution
        if (std.mem.eql(u8, raw_key, "__proto__")) continue;

        const raw_val = std.mem.trim(u8, trimmed[eq_pos + 1 ..], " \t");

        // Strip inline comments from value (anything after unquoted # or ;)
        const stripped_val = stripInlineComment(raw_val);

        const value = try parseValue(allocator, stripped_val);

        // Copy key into allocator memory so it outlives the input slice
        const key_copy = try allocator.dupe(u8, raw_key);
        try head.put(allocator, key_copy, value);
    }

    return root;
}

// ---------------------------------------------------------------------------
// Value parsing helpers
// ---------------------------------------------------------------------------

/// Parse a raw value string into an Expr.
/// Quoted strings → E.String (quotes stripped).
/// "true"/"false" → E.Boolean.
/// "null" → E.Null.
/// Numeric strings → E.Number.
/// Everything else → E.String.
fn parseValue(allocator: std.mem.Allocator, raw: []const u8) OOM!Expr {
    if (raw.len == 0) return Expr.init(E.String, E.String.init(""), Loc.Empty);

    // Double-quoted string
    if (raw.len >= 2 and raw[0] == '"' and raw[raw.len - 1] == '"') {
        const inner = raw[1 .. raw.len - 1];
        const duped = try allocator.dupe(u8, inner);
        return Expr.init(E.String, E.String.init(duped), Loc.Empty);
    }

    // Single-quoted string
    if (raw.len >= 2 and raw[0] == '\'' and raw[raw.len - 1] == '\'') {
        const inner = raw[1 .. raw.len - 1];
        const duped = try allocator.dupe(u8, inner);
        return Expr.init(E.String, E.String.init(duped), Loc.Empty);
    }

    // Boolean
    if (std.mem.eql(u8, raw, "true")) return Expr.init(E.Boolean, E.Boolean{ .value = true }, Loc.Empty);
    if (std.mem.eql(u8, raw, "false")) return Expr.init(E.Boolean, E.Boolean{ .value = false }, Loc.Empty);

    // null
    if (std.mem.eql(u8, raw, "null")) return Expr.init(E.Null, E.Null{}, Loc.Empty);

    // Integer (no decimal point, no exponent)
    if (isIntegerLike(raw)) {
        if (std.fmt.parseFloat(f64, raw)) |n| {
            return Expr.init(E.Number, E.Number{ .value = n }, Loc.Empty);
        } else |_| {}
    }

    // Float
    if (isFloatLike(raw)) {
        if (std.fmt.parseFloat(f64, raw)) |n| {
            return Expr.init(E.Number, E.Number{ .value = n }, Loc.Empty);
        } else |_| {}
    }

    // Plain string
    const duped = try allocator.dupe(u8, raw);
    return Expr.init(E.String, E.String.init(duped), Loc.Empty);
}

/// Strip an inline comment (unquoted # or ;) from a value string.
/// Returns the trimmed value before the comment.
fn stripInlineComment(raw: []const u8) []const u8 {
    var in_double_quote = false;
    var in_single_quote = false;
    var i: usize = 0;
    while (i < raw.len) : (i += 1) {
        const c = raw[i];
        if (c == '"' and !in_single_quote) {
            in_double_quote = !in_double_quote;
        } else if (c == '\'' and !in_double_quote) {
            in_single_quote = !in_single_quote;
        } else if (!in_double_quote and !in_single_quote and (c == '#' or c == ';')) {
            return std.mem.trimRight(u8, raw[0..i], " \t");
        }
    }
    return raw;
}

fn isIntegerLike(s: []const u8) bool {
    if (s.len == 0) return false;
    var start: usize = 0;
    if (s[0] == '-' or s[0] == '+') {
        if (s.len == 1) return false;
        start = 1;
    }
    for (s[start..]) |c| {
        if (c < '0' or c > '9') return false;
    }
    return true;
}

fn isFloatLike(s: []const u8) bool {
    if (s.len == 0) return false;
    var start: usize = 0;
    if (s[0] == '-' or s[0] == '+') {
        if (s.len == 1) return false;
        start = 1;
    }
    var has_dot = false;
    var has_exp = false;
    var has_digit = false;
    var i = start;
    while (i < s.len) : (i += 1) {
        const c = s[i];
        switch (c) {
            '0'...'9' => has_digit = true,
            '.' => {
                if (has_dot or has_exp) return false;
                has_dot = true;
            },
            'e', 'E' => {
                if (has_exp or !has_digit) return false;
                has_exp = true;
                if (i + 1 < s.len and (s[i + 1] == '+' or s[i + 1] == '-')) i += 1;
            },
            else => return false,
        }
    }
    return has_digit and (has_dot or has_exp);
}

/// Traverse root using dot-separated path components, creating E.Object nodes
/// along the way if they don't exist, and return a pointer to the final object.
fn getOrCreateNestedObject(allocator: std.mem.Allocator, root: *E.Object, path: []const u8) OOM!*E.Object {
    var current = root;
    var part_iter = std.mem.splitScalar(u8, path, '.');
    while (part_iter.next()) |part| {
        const trimmed_part = std.mem.trim(u8, part, " \t");
        if (trimmed_part.len == 0) continue;

        if (current.get(trimmed_part)) |existing| {
            if (existing.data == .e_object) {
                current = existing.data.e_object;
            } else {
                // Key exists but is not an object — replace with a fresh object
                const new_obj = Expr.init(E.Object, E.Object{}, Loc.Empty);
                const key_copy = try allocator.dupe(u8, trimmed_part);
                try current.put(allocator, key_copy, new_obj);
                current = current.get(trimmed_part).?.data.e_object;
            }
        } else {
            const new_obj = Expr.init(E.Object, E.Object{}, Loc.Empty);
            const key_copy = try allocator.dupe(u8, trimmed_part);
            try current.put(allocator, key_copy, new_obj);
            current = current.get(trimmed_part).?.data.e_object;
        }
    }
    return current;
}

// ---------------------------------------------------------------------------
// Imports
// ---------------------------------------------------------------------------

const std = @import("std");

const bun = @import("bun");
const logger = bun.logger;
const Loc = logger.Loc;
const ast = bun.ast;
const E = ast.E;
const Expr = ast.Expr;

