        this.builder.append(.lchar, '\n');
        this.builder.append(.lchar, '[');
        this.builder.append(.latin1, section_path);
        this.builder.append(.latin1, "]\n");

        var scalar_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            object,
        );
        defer scalar_iter.deinit();

        // First: scalars and arrays
        while (try scalar_iter.next()) |prop_name| {
            const prop_value = scalar_iter.value;
            if (prop_value.isUndefined() or prop_value.isFunction() or prop_value.isSymbol()) continue;
