                const heap = try bun.default_allocator.alloc(
                    u8,
                    section_path.len + 1 + sub_name.slice().len,
                );
                @memcpy(heap[0..section_path.len], section_path);
                heap[section_path.len] = '.';
                @memcpy(heap[section_path.len + 1 ..], sub_name.slice());
